const resp = $input.first().json;
const docs = resp.data?.data || [];

if (docs.length === 0) {
  return [{ json: { hasDocuments: false, count: 0 } }];
}

const grouped = {};
for (const doc of docs) {
  const dsId = doc.dataset_id || doc.kb_id;
  if (!dsId) continue;

  if (!grouped[dsId]) {
    grouped[dsId] = { dataset_id: dsId, document_ids: [], titles: [] };
  }
  grouped[dsId].document_ids.push(doc.id);
  grouped[dsId].titles.push(doc.name || 'Untitled');
}

const result = Object.values(grouped);
return result.map(g => ({ json: { ...g, hasDocuments: true, count: g.document_ids.length } }));

const results = $('触发解析').all();
let totalDocs = 0;
let successCount = 0;
let failCount = 0;

for (const r of results) {
  const d = r.json;
  const count = d.count || 0;
  totalDocs += count;

  if (d.error || (d.code && d.code !== 0)) {
    failCount += count;
  } else {
    successCount += count;
  }
}

const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
const timeStr = `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;

const summary = `🔄 文档解析兜底任务完成\n⏰ ${dateStr} ${timeStr}\n📊 触发解析: ${successCount}/${totalDocs} 篇${failCount > 0 ? ` (${failCount} 失败)` : ''}`;
const html = `<h4>🔄 文档解析兜底</h4>\n<p><i>${dateStr} ${timeStr}</i></p>\n<p>触发解析: <b>${successCount}/${totalDocs}</b> 篇${failCount > 0 ? ` (<span style="color:red">${failCount} 失败</span>)` : ''}</p>`;

return [{ json: { summary, html, totalDocs, successCount, failCount } }];

